args.sparql:
SELECT ?year WHERE {
  ?election wdt:P991 ?candidate .
  ?candidate wdt:P102 wd:Q1347 .
  ?election wdt:P17 wd:Q30 .
  ?election wdt:P585 ?election_date .
  BIND(YEAR(?election_date) AS ?year)
  FILTER EXISTS {
    ?election wdt:P768 wd:Q1553
  }
}
ORDER BY DESC(?year)
LIMIT 1

SELECT ?year WHERE {
  ?election wdt:P541 wd:Q315 ;
            wdt:P585 ?election_date .
  ?election p:P991 ?statement .
  ?statement ps:P991 ?candidate ;
             pq:P768 wd:Q1553 .
  ?candidate wdt:P102 wd:Q1347 .
  BIND(YEAR(?election_date) AS ?year)
}
ORDER BY DESC(?year)
LIMIT 1
